# --- Rate Limiting (in-memory, per-IP) ---

rate_limit_store = {}
RATE_LIMIT_MAX_ATTEMPTS = 5
RATE_LIMIT_WINDOW_SECONDS = 300  # 5 minutes
RATE_LIMIT_LOCKOUT_SECONDS = 600  # 10 minutes


def _cleanup_rate_limit_store():
    """Remove expired entries from the rate limit store."""
    now = time.time()
    expired_keys = [
        k for k, v in rate_limit_store.items()
        if now - v.get('window_start', 0) > RATE_LIMIT_LOCKOUT_SECONDS + RATE_LIMIT_WINDOW_SECONDS
    ]
    for k in expired_keys:
        del rate_limit_store[k]


def is_rate_limited(identifier):
    """Check if an identifier (IP address) is rate limited."""
    _cleanup_rate_limit_store()
    now = time.time()

    if identifier not in rate_limit_store:
        return False

    entry = rate_limit_store[identifier]

    # Check if currently locked out
    if entry.get('locked_until') and now < entry['locked_until']:
        return True

    # Check if window has expired, reset if so
    if now - entry.get('window_start', 0) > RATE_LIMIT_WINDOW_SECONDS:
        del rate_limit_store[identifier]
        return False

    return False


def record_failed_attempt(identifier):
    """Record a failed authentication attempt."""
    now = time.time()

    if identifier not in rate_limit_store:
        rate_limit_store[identifier] = {
            'attempts': 0,
            'window_start': now,
            'locked_until': None
        }

    entry = rate_limit_store[identifier]

    # Reset window if expired
    if now - entry['window_start'] > RATE_LIMIT_WINDOW_SECONDS:
        entry['attempts'] = 0
        entry['window_start'] = now
        entry['locked_until'] = None

    entry['attempts'] += 1

    if entry['attempts'] >= RATE_LIMIT_MAX_ATTEMPTS:
        entry['locked_until'] = now + RATE_LIMIT_LOCKOUT_SECONDS


def reset_rate_limit(identifier):
    """Reset rate limit for an identifier after successful login."""
    if identifier in rate_limit_store:
        del rate_limit_store[identifier]


# --- Password Hashing ---

def hash_password(password):
    """Hash a password using PBKDF2-HMAC-SHA256 with a random salt."""
    salt = secrets.token_bytes(32)
    iterations = 260000
    dk = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt, iterations)
    # Store as: iterations$salt_hex$hash_hex
    return f"{iterations}${salt.hex()}${dk.hex()}"


def verify_password(stored_hash, password):
    """Verify a password against a stored hash using constant-time comparison."""
    try:
        parts = stored_hash.split('$')
        if len(parts) != 3:
            return False
        iterations = int(parts[0])
        salt = bytes.fromhex(parts[1])
        stored_dk = bytes.fromhex(parts[2])
        dk = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt, iterations)
        return hmac.compare_digest(dk, stored_dk)
    except (ValueError, IndexError):
        return False


# --- Database Setup ---

def get_db():
    """Get a database connection, creating one if needed."""
    if not hasattr(g, 'sqlite_db'):
        g.sqlite_db = sqlite3.connect(app.config['DATABASE'])
        g.sqlite_db.row_factory = sqlite3.Row
        g.sqlite_db.execute("PRAGMA journal_mode=WAL")
        g.sqlite_db.execute("PRAGMA foreign_keys=ON")
    return g.sqlite_db


@app.teardown_appcontext
def close_db(error):
    """Close the database connection at the end of the request."""
    if hasattr(g, 'sqlite_db'):
        g.sqlite_db.close()


def init_db():
    """Initialize the database schema."""
    db = sqlite3.connect(app.config['DATABASE'])
    db.execute("""
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            username TEXT UNIQUE NOT NULL,
            password_hash TEXT NOT NULL,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            is_active INTEGER DEFAULT 1
        )
    """)
    db.execute("""
        CREATE TABLE IF NOT EXISTS auth_tokens (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            user_id INTEGER NOT NULL,
            token_hash TEXT UNIQUE NOT NULL,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            expires_at TIMESTAMP NOT NULL,
            is_revoked INTEGER DEFAULT 0,
            FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
        )
    """)
    db.execute("""
        CREATE TABLE IF NOT EXISTS login_history (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            user_id INTEGER,
            username TEXT,
            ip_address TEXT,
            success INTEGER NOT NULL,
            attempted_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE SET NULL
        )
    """)
    db.execute("CREATE INDEX IF NOT EXISTS idx_auth_tokens_hash ON auth_tokens(token_hash)")
    db.execute("CREATE INDEX IF NOT EXISTS idx_auth_tokens_user ON auth_tokens(user_id)")
    db.execute("CREATE INDEX IF NOT EXISTS idx_login_history_user ON login_history(user_id)")
    db.commit()
    db.close()


# --- Token Management ---

def generate_auth_token(user_id, expires_days=7):
    """Generate a secure authentication token for remember-me functionality."""
    db = get_db()
    raw_token = secrets.token_urlsafe(48)
    token_hash = hashlib.sha256(raw_token.encode('utf-8')).hexdigest()
    expires_at = datetime.utcnow() + timedelta(days=expires_days)

    db.execute(
        "INSERT INTO auth_tokens (user_id, token_hash, expires_at) VALUES (?, ?, ?)",
        (user_id, token_hash, expires_at)
    )
    db.commit()
    return raw_token


def validate_auth_token(raw_token):
    """Validate an authentication token and return the user if valid."""
    db = get_db()
    token_hash = hashlib.sha256(raw_token.encode('utf-8')).hexdigest()

    row = db.execute(
        """SELECT auth_tokens.user_id, users.username, users.is_active
           FROM auth_tokens
           JOIN users ON users.id = auth_tokens.user_id
           WHERE auth_tokens.token_hash = ?
             AND auth_tokens.is_revoked = 0
             AND auth_tokens.expires_at > ?
             AND users.is_active = 1""",
        (token_hash, datetime.utcnow())
    ).fetchone()

    if row:
        return {'id': row['user_id'], 'username': row['username']}
    return None


def revoke_auth_token(raw_token):
    """Revoke a specific authentication token."""
    db = get_db()
    token_hash = hashlib.sha256(raw_token.encode('utf-8')).hexdigest()
    db.execute("UPDATE auth_tokens SET is_revoked = 1 WHERE token_hash = ?", (token_hash,))
    db.commit()


def revoke_all_user_tokens(user_id):
    """Revoke all tokens for a user (e.g., on password change)."""
    db = get_db()
    db.execute("UPDATE auth_tokens SET is_revoked = 1 WHERE user_id = ?", (user_id,))
    db.commit()


def cleanup_expired_tokens():
    """Remove expired and revoked tokens from the database."""
    db = get_db()
    db.execute(
        "DELETE FROM auth_tokens WHERE is_revoked = 1 OR expires_at < ?",
        (datetime.utcnow(),)
    )
    db.commit()


# --- Login History ---

def record_login_attempt(user_id, username, ip_address, success):
    """Record a login attempt in the history."""
    db = get_db()
    db.execute(
        "INSERT INTO login_history (user_id, username, ip_address, success) VALUES (?, ?, ?, ?)",
        (user_id, username, ip_address, 1 if success else 0)
    )
    db.commit()


# --- Session Helpers ---

def login_user(user_id, username, remember=False):
    """Log in a user by setting session data."""
    session.permanent = True
    session['user_id'] = user_id
    session['username'] = username
    session['login_time'] = datetime.utcnow().isoformat()
    # Regenerate session to prevent fixation
    session.modified = True

    token = None
    if remember:
        token = generate_auth_token(user_id, expires_days=30)
    return token


def logout_user():
    """Log out the current user."""
    session.pop('user_id', None)
    session.pop('username', None)
    session.pop('login_time', None)
    session.modified = True


def get_current_user():
    """Get the currently logged-in user from session or token."""
    if 'user_id' in session:
        db = get_db()
        user = db.execute(
            "SELECT id, username, is_active FROM users WHERE id = ? AND is_active = 1",
            (session['user_id'],)
        ).fetchone()
        if user:
            return {'id': user['id'], 'username': user['username']}
        # User no longer valid, clear session
        logout_user()

    # Try remember-me token from cookie
    token = request.cookies.get('remember_token')
    if token:
        user = validate_auth_token(token)
        if user:
            session.permanent = True
            session['user_id'] = user['id']
            session['username'] = user['username']
            session['login_time'] = datetime.utcnow().isoformat()
            return user

    return None


# --- Decorators ---

def login_required(f):
    """Decorator to require authentication for a route."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        user = get_current_user()
        if user is None:
            if request.is_json or request.path.startswith('/api/'):
                return jsonify({'error': 'Authentication required'}), 401
            return redirect(url_for('login_page'))
        g.current_user = user
        return f(*args, **kwargs)
    return decorated_function


def rate_limit_check(f):
    """Decorator to enforce rate limiting on a route."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        ip = request.remote_addr or 'unknown'
        if is_rate_limited(ip):
            entry = rate_limit_store.get(ip, {})
            locked_until = entry.get('locked_until', 0)
            remaining = max(0, int(locked_until - time.time()))
            return jsonify({
                'error': 'Too many failed attempts. Please try again later.',
                'retry_after_seconds': remaining
            }), 429
        return f(*args, **kwargs)
    return decorated_function


