@app.route('/register', methods=['GET', 'POST'])
@rate_limit_check
def register():
    if request.method == 'GET':
        return jsonify({'message': 'POST username and password to register.'})

    data = request.get_json(silent=True) or request.form
    username = data.get('username', '').strip()
    password = data.get('password', '')

    if not username or not password:
        return jsonify({'error': 'Username and password are required.'}), 400

    if len(username) < 3 or len(username) > 64:
        return jsonify({'error': 'Username must be between 3 and 64 characters.'}), 400

    if len(password) < 8:
        return jsonify({'error': 'Password must be at least 8 characters.'}), 400

    if len(password) > 128:
        return jsonify({'error': 'Password must not exceed 128 characters.'}), 400

    db = get_db()
    existing = db.execute("SELECT id FROM users WHERE username = ?", (username,)).fetchone()
    if existing:
        return jsonify({'error': 'Username already taken.'}), 409

    password_hash = hash_password(password)
    cursor = db.execute(
        "INSERT INTO users (username, password_hash) VALUES (?, ?)",
        (username, password_hash)
    )
    db.commit()

    user_id = cursor.lastrowid
    token = login_user(user_id, username, remember=False)

    response_data = {
        'message': 'Registration successful.',
        'user': {'id': user_id, 'username': username}
    }
    resp = jsonify(response_data)
    return resp, 201


@app.route('/login', methods=['GET', 'POST'])
@rate_limit_check
def login_page():
    if request.method == 'GET':
        user = get_current_user()
        if user:
            return jsonify({'message': f"Already logged in as {user['username']}."})
        return jsonify({'message': 'POST username, password, and optionally remember=true to log in.'})

    data = request.get_json(silent=True) or request.form
    username = data.get('username', '').strip()
    password = data.get('password', '')
    remember = data.get('remember', False)
    if isinstance(remember, str):
        remember = remember.lower() in ('true', '1', 'yes')

    ip = request.remote_addr or 'unknown'

    if not username or not password:
        return jsonify({'error': 'Username and password are required.'}), 400

    db = get_db()
    user = db.execute(
        "SELECT id, username, password_hash, is_active FROM users WHERE username = ?",
        (username,)
    ).fetchone()

    # Use constant-time comparison even when user doesn't exist
    if user is None:
        # Hash a dummy password to prevent timing attacks
        verify_password(hash_password("dummy"), password)
        record_login_attempt(None, username, ip, False)
        record_failed_attempt(ip)
        return jsonify({'error': 'Invalid username or password.'}), 401

    if not user['is_active']:
        record_login_attempt(user['id'], username, ip, False)
        record_failed_attempt(ip)
        return jsonify({'error': 'Account is deactivated.'}), 403

    if not verify_password(user['password_hash'], password):
        record_login_attempt(user['id'], username, ip, False)
        record_failed_attempt(ip)
        return jsonify({'error': 'Invalid username or password.'}), 401

    # Successful login
    reset_rate_limit(ip)
    record_login_attempt(user['id'], username, ip, True)
    token = login_user(user['id'], user['username'], remember=remember)

    response_data = {
        'message': 'Login successful.',
        'user': {'id': user['id'], 'username': user['username']}
    }
    resp = jsonify(response_data)

    if token:
        resp.set_cookie(
            'remember_token',
            token,
            max_age=30 * 24 * 3600,  # 30 days
            httponly=True,
            samesite='Lax',
            secure=request.is_secure
        )

    return resp


@app.route('/logout', methods=['GET', 'POST'])
def logout():
    # Revoke remember-me token if present
    token = request.cookies.get('remember_token')
    if token:
        revoke_auth_token(token)

    logout_user()

    resp = jsonify({'message': 'Logged out successfully.'})
    resp.delete_cookie('remember_token')
    return resp


@app.route('/profile')
@login_required
def profile():
    user = g.current_user
    db = get_db()

    # Get recent login history
    history = db.execute(
        """SELECT ip_address, success, attempted_at
           FROM login_history
           WHERE user_id = ?
           ORDER BY attempted_at DESC
           LIMIT 10""",
        (user['id'],)
    ).fetchall()

    login_history = [
        {
            'ip_address': h['ip_address'],
            'success': bool(h['success']),
            'attempted_at': h['attempted_at']
        }
        for h in history
    ]

    # Count active tokens
    active_tokens = db.execute(
        """SELECT COUNT(*) as count FROM auth_tokens
           WHERE user_id = ? AND is_revoked = 0 AND expires_at > ?""",
        (user['id'], datetime.utcnow())
    ).fetchone()['count']

    return jsonify({
        'user': user,
        'session_info': {
            'login_time': session.get('login_time'),
            'active_remember_tokens': active_tokens
        },
        'recent_login_history': login_history
    })


@app.route('/change-password', methods=['POST'])
@login_required
def change_password():
    data = request.get_json(silent=True) or request.form
    current_password = data.get('current_password', '')
    new_password = data.get('new_password', '')

    if not current_password or not new_password:
        return jsonify({'error': 'Current password and new password are required.'}), 400

    if len(new_password) < 8:
        return jsonify({'error': 'New password must be at least 8 characters.'}), 400

    if len(new_password) > 128:
        return jsonify({'error': 'New password must not exceed 128 characters.'}), 400

    user = g.current_user
    db = get_db()

    stored = db.execute(
        "SELECT password_hash FROM users WHERE id = ?", (user['id'],)
    ).fetchone()

    if not verify_password(stored['password_hash'], current_password):
        return jsonify({'error': 'Current password is incorrect.'}), 401

    new_hash = hash_password(new_password)
    db.execute("UPDATE users SET password_hash = ? WHERE id = ?", (new_hash, user['id']))
    db.commit()

    # Revoke all existing tokens for security
    revoke_all_user_tokens(user['id'])

    # Clear remember cookie
    resp = jsonify({'message': 'Password changed successfully. All sessions have been revoked.'})
    resp.delete_cookie('remember_token')

    # Keep current session active
    return resp


